14	// logLevelSetter defines an interface for setting the logging level of a logger.
15	type logLevelSetter interface {
16		SetLevel(string) error
17	}
18	
19	// multiLogLevelSetter sets the log level for multiple logLevelSetters.
20	type multiLogLevelSetter struct {
21		setters []logLevelSetter
22	}
23	
24	func newMultiLogLevelSetter(setters ...logLevelSetter) multiLogLevelSetter {
25		return multiLogLevelSetter{setters: setters}
26	}
27	
28	func (m multiLogLevelSetter) SetLevel(level string) error {
29		allErrs := make([]error, 0, len(m.setters))
30	
31		for _, s := range m.setters {
32			if err := s.SetLevel(level); err != nil {
33				allErrs = append(allErrs, err)
34			}
35		}
36	
37		return errors.Join(allErrs...)
38	}
