40	// zapLogLevelSetter sets the level for a zap logger.
41	type zapLogLevelSetter struct {
42		atomicLevel zap.AtomicLevel
43	}
44	
45	func newZapLogLevelSetter(atomicLevel zap.AtomicLevel) zapLogLevelSetter {
46		return zapLogLevelSetter{
47			atomicLevel: atomicLevel,
48		}
49	}
50	
51	// SetLevel sets the logging level for the zap logger.
52	func (z zapLogLevelSetter) SetLevel(level string) error {
53		parsedLevel, err := zapcore.ParseLevel(level)
54		if err != nil {
55			return err
56		}
57		z.atomicLevel.SetLevel(parsedLevel)
58	
59		return nil
60	}
61	
62	// Enabled returns true if the given level is at or above the current level.
63	func (z zapLogLevelSetter) Enabled(level zapcore.Level) bool {
64		return z.atomicLevel.Enabled(level)
65	}
