9	// newGraphBuiltHealthChecker creates a new graphBuiltHealthChecker.
10	func newGraphBuiltHealthChecker() *graphBuiltHealthChecker {
11		return &graphBuiltHealthChecker{
12			readyCh: make(chan struct{}),
13		}
14	}
15	
16	// graphBuiltHealthChecker is used to check if the initial graph is built and the NGF Pod is ready.
17	type graphBuiltHealthChecker struct {
18		// readyCh is a channel that is initialized in newGraphBuiltHealthChecker and represents if the NGF Pod is ready.
19		readyCh chan struct{}
20		lock    sync.RWMutex
21		ready   bool
22	}
23	
24	// readyCheck returns the ready-state of the Pod. It satisfies the controller-runtime Checker type.
25	// We are considered ready after the first graph is built.
26	func (h *graphBuiltHealthChecker) readyCheck(_ *http.Request) error {
27		h.lock.RLock()
28		defer h.lock.RUnlock()
29	
30		if !h.ready {
31			return errors.New("control plane is not yet ready")
32		}
33	
34		return nil
35	}
36	
37	// setAsReady marks the health check as ready.
38	func (h *graphBuiltHealthChecker) setAsReady() {
39		h.lock.Lock()
40		defer h.lock.Unlock()
41	
42		h.ready = true
43		close(h.readyCh)
44	}
45	
46	// getReadyCh returns a read-only channel, which determines if the NGF Pod is ready.
47	func (h *graphBuiltHealthChecker) getReadyCh() <-chan struct{} {
48		return h.readyCh
49	}
