82	// objectStoreMapAdapter wraps maps of types.NamespacedName to Kubernetes resources
83	// (e.g. map[types.NamespacedName]*v1.Gateway) so that they can be used through objectStore interface.
84	type objectStoreMapAdapter[T client.Object] struct {
85		objects map[types.NamespacedName]T
86	}
87	
88	func newObjectStoreMapAdapter[T client.Object](objects map[types.NamespacedName]T) *objectStoreMapAdapter[T] {
89		return &objectStoreMapAdapter[T]{
90			objects: objects,
91		}
92	}
93	
94	func (m *objectStoreMapAdapter[T]) get(_ ngftypes.ObjectType, nsname types.NamespacedName) client.Object {
95		obj, exist := m.objects[nsname]
96		if !exist {
97			return nil
98		}
99	
100		return obj
101	}
102	
103	func (m *objectStoreMapAdapter[T]) upsert(obj client.Object) {
104		t, ok := obj.(T)
105		if !ok {
106			panic(fmt.Errorf("obj type mismatch: got %T, expected %T", obj, t))
107		}
108		m.objects[client.ObjectKeyFromObject(obj)] = t
109	}
110	
111	func (m *objectStoreMapAdapter[T]) delete(_ ngftypes.ObjectType, nsname types.NamespacedName) {
112		delete(m.objects, nsname)
113	}
