221	type changeTrackingUpdaterObjectTypeCfg struct {
222		// store holds the objects of the gvk. If the store is nil, the objects of the gvk are not persisted.
223		store objectStore
224		// predicate determines how an upsert or delete event should trigger a change.
225		// If predicate is nil, then all upsert or delete events for this object will trigger a change.
226		predicate stateChangedPredicate
227		gvk       schema.GroupVersionKind
228	}
229	
230	// changeTrackingUpdater is an Updater that tracks changes to the cluster state in the multiObjectStore.
231	//
232	// It only works with objects with the GVKs registered in changeTrackingUpdaterObjectTypeCfg. Otherwise, it panics.
233	//
234	// A change is tracked when an object with a GVK has its stateChangedPredicate return true or if its predicate is nil.
235	type changeTrackingUpdater struct {
236		store                  *multiObjectStore
237		stateChangedPredicates map[schema.GroupVersionKind]stateChangedPredicate
238	
239		extractGVK    kinds.MustExtractGVK
240		supportedGVKs gvkList
241	
242		changed bool
243	}
244	
245	func newChangeTrackingUpdater(
246		extractGVK kinds.MustExtractGVK,
247		objectTypeCfgs []changeTrackingUpdaterObjectTypeCfg,
248	) *changeTrackingUpdater {
249		var (
250			supportedGVKs gvkList
251			persistedGVKs gvkList
252	
253			stores                 = make(map[schema.GroupVersionKind]objectStore)
254			stateChangedPredicates = make(map[schema.GroupVersionKind]stateChangedPredicate)
255		)
256	
257		for _, cfg := range objectTypeCfgs {
258			supportedGVKs = append(supportedGVKs, cfg.gvk)
259	
260			if cfg.predicate != nil {
261				stateChangedPredicates[cfg.gvk] = cfg.predicate
262			}
263	
264			if cfg.store != nil {
265				persistedGVKs = append(persistedGVKs, cfg.gvk)
266				stores[cfg.gvk] = cfg.store
267			}
268		}
269	
270		return &changeTrackingUpdater{
271			store:                  newMultiObjectStore(stores, extractGVK, persistedGVKs),
272			extractGVK:             extractGVK,
273			supportedGVKs:          supportedGVKs,
274			stateChangedPredicates: stateChangedPredicates,
275		}
276	}
277	
278	func (s *changeTrackingUpdater) assertSupportedGVK(gvk schema.GroupVersionKind) {
279		if !s.supportedGVKs.contains(gvk) {
280			panic(fmt.Errorf("unsupported GVK %v", gvk))
281		}
282	}
283	
284	func (s *changeTrackingUpdater) upsert(obj client.Object) (changed bool) {
285		objTypeGVK := s.extractGVK(obj)
286	
287		var oldObj client.Object
288	
289		if s.store.persists(objTypeGVK) {
290			oldObj = s.store.get(obj, client.ObjectKeyFromObject(obj))
291	
292			s.store.upsert(obj)
293		}
294	
295		stateChanged, ok := s.stateChangedPredicates[objTypeGVK]
296		if !ok {
297			return true
298		}
299	
300		return stateChanged.upsert(oldObj, obj)
301	}
302	
303	func (s *changeTrackingUpdater) Upsert(obj client.Object) {
304		s.assertSupportedGVK(s.extractGVK(obj))
305	
306		changingUpsert := s.upsert(obj)
307	
308		s.changed = s.changed || changingUpsert
309	}
310	
311	func (s *changeTrackingUpdater) delete(objType ngftypes.ObjectType, nsname types.NamespacedName) (changed bool) {
312		objTypeGVK := s.extractGVK(objType)
313	
314		if s.store.persists(objTypeGVK) {
315			if s.store.get(objType, nsname) == nil {
316				return false
317			}
318	
319			s.store.delete(objType, nsname)
320		}
321	
322		stateChanged, ok := s.stateChangedPredicates[objTypeGVK]
323		if !ok {
324			return true
325		}
326	
327		return stateChanged.delete(objType, nsname)
328	}
329	
330	func (s *changeTrackingUpdater) Delete(objType ngftypes.ObjectType, nsname types.NamespacedName) {
331		s.assertSupportedGVK(s.extractGVK(objType))
332	
333		changingDelete := s.delete(objType, nsname)
334	
335		s.changed = s.changed || changingDelete
336	}
337	
338	// getAndResetChangedStatus returns if a change occurred based on the previous updates (Upserts/Deletes).
339	// It also resets the changed status to false.
340	func (s *changeTrackingUpdater) getAndResetChangedStatus() bool {
341		changed := s.changed
342		s.changed = false
343		return changed
344	}
345	
346	// forceRebuild forces the changed status to true without modifying any cluster state.
347	// This is used when an external event (e.g., a WAF bundle becoming available) must trigger
348	// a graph rebuild without touching the object stores.
349	func (s *changeTrackingUpdater) forceRebuild() {
350		s.changed = true
351	}
