8	// LessObjectMeta compares two ObjectMetas according to the Gateway API conflict resolution guidelines.
9	// See https://gateway-api.sigs.k8s.io/concepts/guidelines/?h=conflict#conflicts
10	func LessObjectMeta(meta1 *metav1.ObjectMeta, meta2 *metav1.ObjectMeta) bool {
11		if meta1.CreationTimestamp.Equal(&meta2.CreationTimestamp) {
12			if meta1.Namespace == meta2.Namespace {
13				return meta1.Name < meta2.Name
14			}
15			return meta1.Namespace < meta2.Namespace
16		}
17	
18		return meta1.CreationTimestamp.Before(&meta2.CreationTimestamp)
19	}
20	
21	// LessClientObject compares two client.Objects and returns true if:
22	// - the first object was created first,
23	// - the objects were created at the same time, or
24	// - the first object's name appears first in alphabetical order.
25	func LessClientObject(obj1 client.Object, obj2 client.Object) bool {
26		create1 := obj1.GetCreationTimestamp()
27		create2 := obj2.GetCreationTimestamp()
28	
29		if create1.Time.Equal(create2.Time) {
30			if obj1.GetNamespace() == obj2.GetNamespace() {
31				return obj1.GetName() < obj2.GetName()
32			}
33			return obj1.GetNamespace() < obj2.GetNamespace()
34		}
35	
36		return create1.Time.Before(create2.Time)
37	}
