18	// NewControllerCollector creates a new ControllerCollector.
19	func NewControllerCollector(constLabels map[string]string) *ControllerCollector {
20		nc := &ControllerCollector{
21			eventBatchProcessDuration: prometheus.NewHistogram(
22				prometheus.HistogramOpts{
23					Name:        "event_batch_processing_milliseconds",
24					Namespace:   metrics.Namespace,
25					Help:        "Duration in milliseconds of event batch processing",
26					ConstLabels: constLabels,
27					Buckets:     []float64{500, 1000, 5000, 10000, 30000},
28				},
29			),
30		}
31		return nc
32	}
33	
34	// ObserveLastEventBatchProcessTime adds the last event batch processing time to the histogram.
